// ── Filter: only firing alerts from namespace 'demo' ──────────────────────
// ── Dedup: ignore fingerprints already processed within the last 10 minutes ─
const body = $input.first().json.body || $input.first().json;
const now = Date.now();
const TTL = 10 * 60 * 1000; // 10 minutes

// 1. Keep only firing alerts from the demo namespace
const demoAlerts = (body.alerts || []).filter(a =>
  a.status === 'firing' &&
  (a.labels?.namespace === 'demo' || body.commonLabels?.namespace === 'demo')
);

if (demoAlerts.length === 0) {
  console.log('[Filter] No firing demo alerts — stopping execution');
  return [];
}

// 2. Deduplication using workflow static data (survives workflow restarts)
const store = $getWorkflowStaticData('global');
if (!store.seen) store.seen = {};

// Evict expired entries
for (const [fp, ts] of Object.entries(store.seen)) {
  if (now - ts > TTL) delete store.seen[fp];
}

// Filter out already-seen fingerprints
const newAlerts = demoAlerts.filter(alert => {
  const fp = alert.fingerprint ||
    [alert.labels?.alertname, alert.labels?.namespace, alert.labels?.pod].join('-');
  if (store.seen[fp]) {
    const age = Math.round((now - store.seen[fp]) / 1000);
    console.log(`[Dedup] Alert ${fp} already processed ${age}s ago — skipping`);
    return false;
  }
  store.seen[fp] = now;
  return true;
});

if (newAlerts.length === 0) {
  console.log('[Dedup] All alerts are duplicates within TTL — stopping execution');
  return [];
}

console.log(`[Filter+Dedup] Passing ${newAlerts.length} new alert(s) to SRE Agent`);
return [{ json: { ...($input.first().json), body: { ...body, alerts: newAlerts } } }];

// Parse and enrich the SRE Agent response for downstream nodes
const agentResponse = $input.first().json;
const results = agentResponse.results || [];

if (results.length === 0) {
  console.warn('[Parse] SRE Agent returned 0 results');
  return [{ json: {
    alert: 'unknown', namespace: 'unknown', severity: 'unknown',
    classification: 'Unknown', rootCause: 'No results from agent',
    autoRemediated: false, prUrl: 'none', argoCDSync: false,
    runbook: '', investigationSteps: 0
  }}];
}

const enriched = results.map(r => ({
  alert:            r.alert_name,
  namespace:        r.namespace,
  severity:         r.severity,
  classification:   r.classification,
  rootCause:        r.root_cause,
  autoRemediated:   r.auto_remediation_applied,
  prUrl:            r.git_pr_url || 'none',
  argoCDSync:       r.argocd_sync_triggered,
  runbook:          (r.runbook || []).map(s => `${s.order}. [${s.action}] ${s.description} — ${s.command || 'n/a'}`).join('\n'),
  investigationSteps: (r.investigation_log || []).length,
}));

console.log(`[Parse] ${enriched.length} result(s): ${enriched.map(e => e.classification).join(', ')}`);
return enriched.map(e => ({ json: e }));

// Build a human-readable incident report
const data = $input.first().json;
const timestamp = new Date().toISOString();

const severityEmoji = { critical: '🔴', warning: '🟡', info: '🔵' }[data.severity] || '⚪';

const lines = [
  `${severityEmoji} *SRE Copilot Incident Report*`,
  `*Timestamp:*      ${timestamp}`,
  `*Alert:*          ${data.alert}`,
  `*Namespace:*      ${data.namespace}`,
  `*Severity:*       ${(data.severity || '').toUpperCase()}`,
  `*Classification:* ${data.classification}`,
  `*Root Cause:*     ${data.rootCause}`,
  '',
  `*Auto-Remediated:* ${data.autoRemediated ? '✅ Yes' : '❌ No'}`,
  data.prUrl && data.prUrl !== 'none' ? `*GitOps PR:*       ${data.prUrl}` : null,
  data.argoCDSync ? `*ArgoCD Sync:*     triggered ✅` : null,
  '',
  `*Runbook:*`,
  data.runbook || '(no runbook generated)',
  '',
  `*Investigation steps collected:* ${data.investigationSteps}`,
].filter(l => l !== null).join('\n');

console.log('AUDIT:', JSON.stringify({
  timestamp, alert: data.alert, namespace: data.namespace,
  severity: data.severity, classification: data.classification,
  autoRemediated: data.autoRemediated, prUrl: data.prUrl,
}));

return [{ json: { report: lines, ...data, timestamp } }];
